   237→}
   238→
   239→func NewTypedMaxOfRateLimiter[T comparable](limiters ...TypedRateLimiter[T]) TypedRateLimiter[T] {
   240→	return &TypedMaxOfRateLimiter[T]{limiters: limiters}
   241→}
