   243→func (r *TypedMaxOfRateLimiter[T]) NumRequeues(item T) int {
   244→	ret := 0
   245→	for _, limiter := range r.limiters {
   246→		curr := limiter.NumRequeues(item)
   247→		if curr > ret {
